import java.util.Scanner;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS attacks
        String safeUserInput = sanitizeInput(userInput);

        String greetingMessage = "Hello, " + safeUserInput + "! Welcome to our website.";

        System.out.println(greetingMessage);
    }

    private static String sanitizeInput(String userInput) {
        // Replace characters that are part of HTML syntax with their corresponding HTML entities
        return userInput.replaceAll("<", "&lt;")
                        .replaceAll(">", "&gt;")
                        .replaceAll("&", "&amp;")
                        .replaceAll("\"", "&quot;")
                        .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
